package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.Field;
import java.util.Map;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.Assertions;
import org.apache.commons.csv.Lexer;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.stubbing.Answer;
import org.mockito.invocation.InvocationOnMock;

class CSVParserTest {

    private CSVFormat formatMock;
    private Reader reader;

    @BeforeEach
    void setUp() {
        formatMock = mock(CSVFormat.class);
        reader = new StringReader("header1,header2\nvalue1,value2\n");
    }

    @Test
    void testConstructor_NullReader_ThrowsException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            new CSVParser(null, formatMock);
        });
        assertEquals("reader", ex.getMessage());
    }

    @Test
    void testConstructor_NullFormat_ThrowsException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> {
            new CSVParser(reader, null);
        });
        assertEquals("format", ex.getMessage());
    }

    @Test
    void testConstructor_ValidArguments_InitializesFields() throws Exception {
        // Mock Assertions.notNull to throw NPE with message for null
        Answer<Void> notNullAnswer = invocation -> {
            Object arg = invocation.getArgument(0);
            String name = invocation.getArgument(1);
            if (arg == null) {
                throw new NullPointerException(name);
            }
            return null;
        };

        try {
            // Use reflection to replace Assertions.notNull with our mock via Mockito spy
            // Because Assertions.notNull is static, we cannot mock it with Mockito 3 without mockito-inline
            // So we use a workaround: temporarily replace Assertions class with a spy using a custom classloader is complex
            // Instead, just test without mocking Assertions.notNull, since it just throws NPE on null (already tested)
            // So here, just spy formatMock.validate() and test constructor normally

            doNothing().when(formatMock).validate();

            CSVParser parser = new CSVParser(reader, formatMock);

            // Verify format.validate() called
            verify(formatMock, times(1)).validate();

            // Validate that format field is set correctly via reflection
            Field formatField = CSVParser.class.getDeclaredField("format");
            formatField.setAccessible(true);
            Object formatValue = formatField.get(parser);
            assertSame(formatMock, formatValue);

            // Validate lexer field is not null
            Field lexerField = CSVParser.class.getDeclaredField("lexer");
            lexerField.setAccessible(true);
            Object lexerValue = lexerField.get(parser);
            assertNotNull(lexerValue);

            // Validate headerMap is initialized and not null
            Field headerMapField = CSVParser.class.getDeclaredField("headerMap");
            headerMapField.setAccessible(true);
            Map<?, ?> headerMap = (Map<?, ?>) headerMapField.get(parser);
            assertNotNull(headerMap);
        } catch (Exception e) {
            throw e;
        }
    }
}
